#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#include <omp.h>

void bpnn_layerforward_omp(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid)
{
    int num_blocks = in / HEIGHT;
    float weight_matrix[HEIGHT][WIDTH];
    float input_node[HEIGHT];

    #pragma omp parallel num_threads(THREADS)
    {
        int by = omp_get_thread_num() / HEIGHT;
        int tx = omp_get_thread_num() % WIDTH;
        int ty = omp_get_thread_num() / WIDTH;

        if (by >= num_blocks) return;

        int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );  
        int index_in = HEIGHT * by + ty + 1;

        if (tx == 0)
            input_node[ty] = input_cuda[index_in];

        #pragma omp barrier

        weight_matrix[ty][tx] = input_hidden_cuda[index];
        #pragma omp barrier

        weight_matrix[ty][tx] = weight_matrix[ty][tx] * input_node[ty];
        #pragma omp barrier

        for (int i = 1; i <= HEIGHT; i = i*2) {
            int power_two = i;
            if (ty % power_two == 0)
                weight_matrix[ty][tx] = weight_matrix[ty][tx] + weight_matrix[(ty + power_two/2)][tx];

            #pragma omp barrier
        }

        input_hidden_cuda[index] = weight_matrix[ty][tx];
        #pragma omp barrier

        if (tx == 0) {
            hidden_partial_sum[by * hid + ty] = weight_matrix[tx][ty];
        }
    }
}

void bpnn_adjust_weights_omp(float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw)  									
{
    int num_blocks = in / HEIGHT;

    #pragma omp parallel num_threads(THREADS)
    {
        int by = omp_get_thread_num() / HEIGHT;
        int tx = omp_get_thread_num() % WIDTH;
        int ty = omp_get_thread_num() / WIDTH;

        if (by >= num_blocks) return;

        int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 );  
        int index_y = HEIGHT * by + ty + 1;
        int index_x = tx + 1;

        w[index] += ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
        oldw[index] = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));

        #pragma omp barrier

        if (ty == 0 && by ==0){
            w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
            oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
        }
    }
}
